def test_extract_form_id_from_public_url():
    assert extract_form_id("https://docs.google.com/forms/d/e/abc123/viewform") == "abc123"
    assert extract_form_id("https://docs.google.com/forms/d/xyz789/edit") == "xyz789"


def test_import_google_form_from_html_maps_supported_questions():
    form = import_google_form_from_html("abc123", SAMPLE_HTML)

    assert form.title == "Cuestionario diario"
    assert form.submit_url == "https://docs.google.com/forms/d/e/abc123/formResponse"
    assert [question.title for question in form.questions] == ["Como te encuentras?", "Quieres descansar?"]
    assert form.questions[0].entry_id == "entry.222"
    assert form.questions[0].type == "checkbox"
    assert [option.label for option in form.questions[0].options] == ["Tengo sed", "Tengo frio"]


def test_submit_google_form_posts_entry_values():
    requests = []

    def handler(request: httpx.Request) -> httpx.Response:
        requests.append(request)
        return httpx.Response(200, text="OK")

    form = import_google_form_from_html("abc123", SAMPLE_HTML)
    result = submit_google_form(
        form,
        {"111": ["Tengo sed"], "333": ["No"]},
        client=httpx.Client(transport=httpx.MockTransport(handler)),
    )

    assert result.submitted is True
    body = requests[0].content.decode()
    assert "entry.222=Tengo+sed" in body
    assert "entry.444=No" in body
